var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"리코리스, 저기 오십니다.","JPN":"リコリス、あちらにいらっしゃいます。","ENG":"Lycoris, there they come.","TWN":"莉克麗絲，他們來了。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"오, 자네들은…….","JPN":"おお、君たちは……","ENG":"Oh, you’re...","TWN":"喔，你們是……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"플로라 메이드 서비스의 메이드들이군요.","JPN":"フローラメイドサービスのメイドさんですね。","ENG":"The maids from the Flora Maid Service.","TWN":"芙蘿拉女僕服務公司的女僕們。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"그렇습니다. 이렇게 만나뵙게 되어 영광입니다. 주인님.","JPN":"はい。お会いできて光栄です。ご主人様。","ENG":"Yes. We’re very honored to see you, Master.","TWN":"是的，主人，很榮幸見到您。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"저는 릴리. 그리고 이쪽은…….","JPN":"私はリリー、そしてこちらは……","ENG":"I’m Lily, and this is...","TWN":"我是莉莉，這位是…"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"리코리스야. 부르고 싶은 대로 불러.","JPN":"リコリスよ。適当に呼んで。","ENG":"Lycoris. Or just call me whatever you’d like.","TWN":"我是莉克麗絲，你想怎麼叫我都可以。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"딱히 나도 낯간지럽게 주인님이라고 부를 생각은 없으니까.","JPN":"別に私だってご主人様と呼びたいわけじゃないから。","ENG":"I’m not calling you Master, it’s embarrassing.","TWN":"反正我也不想噁心地稱呼你主人。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하하, 괜찮네. 깡통이라고 불렀던 직원들도 있는 마당에.","JPN":"ははは、いいんだ。ボロ缶と呼んでいる社員もいるしな。","ENG":"Hah hah, I don’t mind. Some of my employees even call me a tin can, you know.","TWN":"哈哈，沒關係，有些員工還會叫我罐頭呢。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그런데 여긴 어쩐 일인가? 모네 양이 걱정돼서?","JPN":"ところで、ここには何の用かね？　モネが心配だったのか？","ENG":"But why are you here? Were you worried about Mone?","TWN":"不過，你們來這裡有什麼事嗎？是因為擔心莫妮？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"누, 누가 누굴 걱정해?","JPN":"だ、誰が誰を心配するっていうの？","ENG":"W-worried? No one’s worried about anything!","TWN":"才…才不是咧！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"그게……! 그냥 괜히 사고치면 골치 아파지니까 그렇지!","JPN":"……そう！　ただ余計な事故でも起こしたらまずいから監視にきただけ！","ENG":"I’m just... Well, we’re only here because it’s on us if Mone gets into trouble!","TWN":"我…我們是怕他闖禍給我們惹麻煩！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"모네는 메이드로서 아직 부족합니다.","JPN":"モネはメイドとしてまだ未熟です。","ENG":"Mone is still a trainee.","TWN":"莫妮還不是那麼成熟的女僕。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"평소에도 몸가짐을 바르게 하는지 늘 지켜 봐야죠.","JPN":"普段から身だしなみをちゃんとしているのか、常に見守らなければなりません。","ENG":"We’re here to check if Mone is acting accordingly as a maid.","TWN":"我們必須幫他注意平時的言行舉止。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"뭐……. 가급적이면 나서고 싶지는 않았지만.","JPN":"まあ……なるべく表には出たくはなかったけど。","ENG":"Although... we didn’t really want to be seen.","TWN":"嗯…可以的話，我是不太想這樣啦。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"응? 어째서인가?","JPN":"うん？　どうして？","ENG":"Hm? Why not?","TWN":"嗯？為什麼？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"혹시 혼자 먼 길을 온 모네 양에게 상처를 주고 싶지 않아서?!","JPN":"もしかしてモネを傷つけたくないからか？","ENG":"You didn’t want to hurt Mone’s feelings?","TWN":"你是怕大老遠回來的莫妮，知道後心裡會受傷嗎？！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};